/* AdminBbsMapper.selectBbsMstTotalCount */
SELECT
	COUNT(1)
FROM
	TB_BOARD_MST


		AND BBS_TYPE = #{bbsType}


		AND SITE_CODE = #{siteCode}


		AND BBS_NM LIKE CONCAT('%', #{bbsNm}, '%')

/* AdminBbsMapper.selectBbsMstList */ SELECT BBS_SEQ AS bbsSeq ,BBS_NM AS bbsNm ,BBS_TYPE AS bbsType ,FIXING_YN AS fixingYn ,REPLY_YN AS replyYn ,FILE_ATCH_YN AS fileAtchYn ,FILE_EXT_FLTER AS fileExtFlter ,FILE_ATCH_CO AS fileAtchCo ,VIEWER_YN AS viewerYn ,PAGE_LIST_CO AS pageListCo ,PRHIBT_WRD AS prhibtWrd ,USE_YN AS useYn ,REG_ID AS regId ,DATE_FORMAT(REG_DT, '%Y-%m-%d %H:%i:%s') AS regDt ,UPD_ID AS updId ,DATE_FORMAT(UPD_DT, '%Y-%m-%d %H:%i:%s') AS updDt ,EDITR_YN AS editrYn ,FILE_LMTT_SIZE AS fileLmttSize ,SITE_CODE AS siteCode ,INSERT_YN AS insertYn ,UPDATE_YN AS updateYn ,DELETE_YN AS deleteYn FROM TB_BOARD_MST
AND BBS_TYPE = #{bbsType}
AND SITE_CODE = #{siteCode}
AND BBS_NM LIKE CONCAT('%', #{bbsNm}, '%')
ORDER BY REG_DT DESC LIMIT #{offset}, #{pageSize}

mapper.insert:
/* AdminBbsMapper.insertBbs */
INSERT INTO TB_BOARD_MST (
	 BBS_SEQ
	,BBS_NM
	,BBS_TYPE
	,FIXING_YN
	,REPLY_YN
	,FILE_ATCH_YN
	,FILE_EXT_FLTER
	,FILE_ATCH_CO
	,VIEWER_YN
	,PAGE_LIST_CO
	,PRHIBT_WRD
	,EDITR_YN
	,FILE_LMTT_SIZE
	,SITE_CODE
	,INSERT_YN
	,UPDATE_YN
	,DELETE_YN
	,USE_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{bbsSeq}
	,#{bbsNm}
	,#{bbsType}
	,#{fixingYn}
	,#{replyYn}
	,#{fileAtchYn}
	,#{fileExtFlter}
	,#{fileAtchCo}
	,#{viewerYn}
	,#{pageListCo}
	,#{prhibtWrd}
	,#{editrYn}
	,#{fileLmttSize}
	,#{siteCode}
	,IFNULL(#{insertYn}, 'N')
	,IFNULL(#{updateYn}, 'N')
	,IFNULL(#{deleteYn}, 'N')
	,#{useYn}
	,#{userId}
	,now()
	,#{userId}
	,now()
)

/* AdminBbsMapper.selectBbsFieldSeq */
INSERT INTO TB_BOARD_MST_FIELD (
	 BBS_SEQ
	,SEQ
	,COLUMN_NM
	,COLUMN_SJ
	,USE_YN
	,ESSNTL_YN
	,DETAIL_YN
	,LIST_YN
	,FIELD_SIZE
	,SEARCH_YN
	,LIST_ORDR
) VALUES (
	 #{bbsSeq}
	,#{seq}
	,#{columnNm}
	,#{columnSj}
	,IFNULL(#{useYn}, 'N')
	,IFNULL(#{essntlYn}, 'N')
	,IFNULL(#{detailYn}, 'N')
	,IFNULL(#{listYn}, 'N')
	,#{fieldSize}
	,IFNULL(#{searchYn}, 'N')
	,NULLIF(#{listOrdr}, '')
)

mapper.update:
/* AdminBbsMapper.updateBbs */
UPDATE TB_BOARD_MST
SET
	 BBS_NM 			= #{bbsNm}
	,BBS_TYPE 			= #{bbsType}
	,FIXING_YN 			= #{fixingYn}
	,REPLY_YN 			= #{replyYn}
	,FILE_ATCH_YN 		= #{fileAtchYn}
	,FILE_EXT_FLTER 	= #{fileExtFlter}
	,FILE_ATCH_CO 		= #{fileAtchCo}
	,VIEWER_YN 			= #{viewerYn}
	,PAGE_LIST_CO 		= #{pageListCo}
	,PRHIBT_WRD 		= #{prhibtWrd}
	,EDITR_YN 			= #{editrYn}
	,FILE_LMTT_SIZE 	= #{fileLmttSize}
	,SITE_CODE 			= #{siteCode}
	,INSERT_YN 			= IFNULL(#{insertYn}, 'N')
	,UPDATE_YN 			= IFNULL(#{updateYn}, 'N')
	,DELETE_YN 			= IFNULL(#{deleteYn}, 'N')
	,USE_YN 			= #{useYn}
	,UPD_ID 			= #{userId}
	,UPD_DT 			= now()
WHERE
	BBS_SEQ = #{bbsSeq}

/* AdminBbsMapper.updateBbsField */
UPDATE TB_BOARD_MST_FIELD
SET
	 COLUMN_NM		= #{columnNm}
	,COLUMN_SJ		= #{columnSj}
	,USE_YN			= IFNULL(#{useYn}, 'N')
	,ESSNTL_YN		= IFNULL(#{essntlYn}, 'N')
	,DETAIL_YN		= IFNULL(#{detailYn}, 'N')
	,LIST_YN		= IFNULL(#{listYn}, 'N')
	,FIELD_SIZE		= #{fieldSize}
	,SEARCH_YN		= IFNULL(#{searchYn}, 'N')
	,LIST_ORDR		= NULLIF(#{listOrdr}, '')
WHERE
	BBS_SEQ = #{bbsSeq}
AND
	SEQ = #{seq}

mapper.delete:
/* AdminBbsMapper.deleteBbs */
DELETE FROM TB_BOARD_MST
WHERE
	BBS_SEQ = #{bbsSeq}

/* AdminBbsMapper.deleteBbsField */
DELETE FROM TB_BOARD_MST_FIELD
WHERE
	BBS_SEQ = #{bbsSeq}

mapper.select:
/* AdminBbsMapper.selectBbsList */ SELECT A.NTT_SEQ AS nttSeq ,A.BBS_SEQ AS bbsSeq ,A.NTT_SJ AS nttSj ,A.NTT_RDCNT AS nttRdcnt ,A.REG_ID AS regId ,DATE_FORMAT(A.REG_DT, '%Y-%m-%d') AS regDt ,A.SECRET_YN AS secretYn FROM TB_BOARD A LEFT JOIN TB_MENU B ON A.BBS_SEQ = B.BBS_SEQ AND B.MENU_ID = #{menuId} AND B.MENU_PID = #{menuPid} AND B.SITE_CODE = 'admin' WHERE A.DEL_YN = 'N'
AND A.NTT_SJ LIKE CONCAT('%', #{nttSj}, '%')
ORDER BY A.REG_DT DESC LIMIT #{offset}, #{pageSize}

/* AdminBbsMapper.bbsPassword */
SELECT
	COUNT(1)
FROM
	TB_BOARD
WHERE
	BBS_SEQ = #{bbsSeq}
AND
	NTT_SEQ = #{nttSeq}
AND
	NTT_PASSWORD = #{nttPassword}

