/* AdminBbsMapper.insertBoard */
INSERT INTO TB_BOARD (
	 BBS_SEQ
	,NTT_SEQ
	,SITE_CODE
	,NTT_SJ
	,NTT_CN
	,NTT_RDCNT
	,NTT_PASSWORD
	,ATCHFILENO
	,BGNDE
	,ENDDE
	,USE_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
	,DEL_YN
	,SECRET_YN
) VALUES (
	 #{bbsSeq}
	,#{nttSeq}
	,#{siteCode}
	,#{nttSj}
	,#{nttCn}
	,0
	,#{nttPassword}
	,#{atchfileno}
	,#{bgnde}
	,#{endde}
	,#{useYn}
	,#{userId}
	,now()
	,#{userId}
	,now()
	,'N'
	,#{secretYn}
)

mapper.update:
/* AdminBbsMapper.updateBoard */
UPDATE
	TB_BOARD
SET
	 SITE_CODE = #{siteCode}
	,NTT_SJ = #{nttSj}
	,NTT_CN = #{nttCn}
	,NTT_PASSWORD = #{nttPassword}
	,ATCHFILENO = #{atchfileno}
	,BGNDE = #{bgnde}
	,ENDDE = #{endde}
	,USE_YN = #{useYn}
	,UPD_ID = #{userId}
	,UPD_DT = now()
	,SECRET_YN = #{secretYn}
WHERE
	BBS_SEQ = #{bbsSeq}
AND
	NTT_SEQ = #{nttSeq}

/* AdminBbsMapper.deleteBoard */
UPDATE
	TB_BOARD
SET
	 DEL_YN = 'Y'
	,UPD_ID = #{userId}
	,UPD_DT = now()
WHERE
	BBS_SEQ = #{bbsSeq}
AND
	NTT_SEQ = #{nttSeq}

/* AdminBbsMapper.updateBoardRdcnt */
UPDATE
	TB_BOARD
SET
	 NTT_RDCNT = NTT_RDCNT + 1
WHERE
	BBS_SEQ = #{bbsSeq}
AND
	NTT_SEQ = #{nttSeq}
